import{_ as i,o as a,c as g,a8 as u}from"./chunks/framework.DvHWw5tv.js";const y=JSON.parse('{"title":"useScrollComputed","description":"","frontmatter":{},"headers":[],"relativePath":"design/hooks/useScroll.md","filePath":"design/hooks/useScroll.md"}'),e={name:"design/hooks/useScroll.md"};function o(s,n,d,h,t,l){return a(),g("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775839268000"},[...n[0]||(n[0]=[u('<h1 id="usescrollcomputed" tabindex="-1">useScrollComputed <a class="header-anchor" href="#usescrollcomputed" aria-label="Permalink to “useScrollComputed”">​</a></h1><h3 id="usescrollcomputed-滚动条样式统一管理-hooks" tabindex="-1">useScrollComputed：滚动条样式统一管理 Hooks <a class="header-anchor" href="#usescrollcomputed-滚动条样式统一管理-hooks" aria-label="Permalink to “useScrollComputed：滚动条样式统一管理 Hooks”">​</a><span class="pagefind-pinyin" aria-hidden="true">useScrollComputed：gundongtiaoyangshitongyiguanli Hooks useScrollComputed： gun dong tiao yang shi tong yi guan li Hooks ugdtystygl </span></h3><h2 id="痛点来源" tabindex="-1">痛点来源 <a class="header-anchor" href="#痛点来源" aria-label="Permalink to “痛点来源”">​</a><span class="pagefind-pinyin" aria-hidden="true">tongdianlaiyuan tong dian lai yuan tdly </span></h2><p>原生浏览器滚动条样式差异大、难以统一，且在现代 UI 设计中常常需要自定义外观（颜色、宽度、hover 效果）。常见问题包括：<span class="pagefind-pinyin" aria-hidden="true">yuanshengliulanqigundongtiaoyangshichayida、nanyitongyi，qiezaixiandai UI shejizhongchangchangxuyaozidingyiwaiguan（yanse、kuandu、hover xiaoguo）。changjianwentibaokuo： yuan sheng liu lan qi gun dong tiao yang shi cha yi da 、 nan yi tong yi ， qie zai xian dai UI she ji zhong chang chang xu yao zi ding yi wai guan （ yan se 、 kuan du 、hover xiao guo ）。 chang jian wen ti bao kuo ： ysllqgdtyscyd、nyty，qzxd sjzccxyzdywg（ys、kd、xg）cjwtbk：</span></p><ul><li>全局滚动条样式无法通过普通 CSS 变量直接控制（需作用于 <code>:root</code>）<span class="pagefind-pinyin" aria-hidden="true">quanjugundongtiaoyangshiwufatongguoputong CSS bianliangzhijiekongzhi（xuzuoyongyu ） quan ju gun dong tiao yang shi wu fa tong guo pu tong CSS bian liang zhi jie kong zhi （ xu zuo yong yu ） qjgdtyswftgpt blzjkz（xzyy </span></li><li>不同组件（如 Scrollbar、虚拟列表、容器溢出）对滚动条样式的需求重复<span class="pagefind-pinyin" aria-hidden="true">butongzujian（ru Scrollbar、xuniliebiao、rongqiyichu）duigundongtiaoyangshidexuqiuzhongfu bu tong zu jian （ ru Scrollbar、 xu ni lie biao 、 rong qi yi chu ） dui gun dong tiao yang shi de xu qiu zhong fu btzj（r xnlb、rqyc）dgdtysdxqzf</span></li><li>动态主题切换时，滚动条颜色需实时更新并在组件销毁时清理<span class="pagefind-pinyin" aria-hidden="true">dongtaizhutiqiehuanshi，gundongtiaoyansexushishigengxinbingzaizujianxiaohuishiqingli dong tai zhu ti qie huan shi ， gun dong tiao yan se xu shi shi geng xin bing zai zu jian xiao hui shi qing li dtztqhs，gdtysxssgxbzzjxhsql</span></li><li>局部滚动条与全局滚动条需求并存（全局影响整个页面，局部仅影响容器）<span class="pagefind-pinyin" aria-hidden="true">jubugundongtiaoyuquanjugundongtiaoxuqiubingcun（quanjuyingxiangzhenggeyemian，jubujinyingxiangrongqi） ju bu gun dong tiao yu quan ju gun dong tiao xu qiu bing cun （ quan ju ying xiang zheng ge ye mian ， ju bu jin ying xiang rong qi ） jbgdtyqjgdtxqbc（qjyxzgym，jbjyxrq）</span></li><li>宽度/高度单位处理不一致，易遗漏 <code>px</code> 转换<span class="pagefind-pinyin" aria-hidden="true">kuandu/gaodudanweichulibuyizhi，yiyilou zhuanhuan kuan du / gao du dan wei chu li bu yi zhi ， yi yi lou zhuan huan kd/gddwclbyz，yyl zh</span></li><li>未清理的全局样式会导致多实例或切换时样式残留、污染<span class="pagefind-pinyin" aria-hidden="true">weiqinglidequanjuyangshihuidaozhiduoshilihuoqiehuanshiyangshicanliu、wuran wei qing li de quan ju yang shi hui dao zhi duo shi li huo qie huan shi yang shi can liu 、 wu ran wqldqjyshdzdslhqhsyscl、wr</span></li></ul><p>若每个滚动相关组件都自行处理这些逻辑，会导致样式不统一、清理遗漏、主题适配困难。<span class="pagefind-pinyin" aria-hidden="true">ruomeigegundongxiangguanzujianduzihangchulizhexieluoji，huidaozhiyangshibutongyi、qingliyilou、zhutishipeikunnan。 ruo mei ge gun dong xiang guan zu jian du zi hang chu li zhe xie luo ji ， hui dao zhi yang shi bu tong yi 、 qing li yi lou 、 zhu ti shi pei kun nan 。 rmggdxgzjdzhclzxlj，hdzysbty、qlyl、ztspkn。</span></p><h2 id="设计目标" tabindex="-1">设计目标 <a class="header-anchor" href="#设计目标" aria-label="Permalink to “设计目标”">​</a><span class="pagefind-pinyin" aria-hidden="true">shejimubiao she ji mu biao sjmb </span></h2><p>本文件提供两套互补的滚动条样式管理方案：<span class="pagefind-pinyin" aria-hidden="true">benwenjiantigongliangtaohubudegundongtiaoyangshiguanlifangan： ben wen jian ti gong liang tao hu bu de gun dong tiao yang shi guan li fang an ： bwjtglthbdgdtysglfa：</span></p><ul><li><code>useScrollStyles</code>：<strong>全局滚动条样式控制</strong>，动态注入到 <code>:root</code>，并自动清理<span class="pagefind-pinyin" aria-hidden="true">：quanjugundongtiaoyangshikongzhi，dongtaizhurudao ，bingzidongqingli ： quan ju gun dong tiao yang shi kong zhi ， dong tai zhu ru dao ， bing zi dong qing li ：qjgdtyskz，dtzrd bzdql</span></li><li><code>useScrollVariables</code>：<strong>局部滚动条样式控制</strong>，返回 CSS 变量对象，适用于单个容器<span class="pagefind-pinyin" aria-hidden="true">：jubugundongtiaoyangshikongzhi，fanhui CSS bianliangduixiang，shiyongyudangerongqi ： ju bu gun dong tiao yang shi kong zhi ， fan hui CSS bian liang dui xiang ， shi yong yu dan ge rong qi ：jbgdtyskz，fh bldx，syydgrq</span></li></ul><p>共同目标是：<strong>统一滚动条视觉规范，支持全局与局部双模式，完美适配动态主题与组件生命周期</strong>。<span class="pagefind-pinyin" aria-hidden="true">gongtongmubiaoshi：tongyigundongtiaoshijueguifan，zhichiquanjuyujubushuangmoshi，wanmeishipeidongtaizhutiyuzujianshengmingzhouqi。 gong tong mu biao shi ： tong yi gun dong tiao shi jue gui fan ， zhi chi quan ju yu ju bu shuang mo shi ， wan mei shi pei dong tai zhu ti yu zu jian sheng ming zhou qi 。 gtmbs：tygdtsjgf，zcqjyjbsms，wmspdtztyzjsmzq。</span></p><h2 id="核心工具对比" tabindex="-1">核心工具对比 <a class="header-anchor" href="#核心工具对比" aria-label="Permalink to “核心工具对比”">​</a><span class="pagefind-pinyin" aria-hidden="true">hexingongjuduibi he xin gong ju dui bi hxgjdb </span></h2><table tabindex="0"><thead><tr><th>Hook</th><th>适用场景<span class="pagefind-pinyin" aria-hidden="true">shiyongchangjing shi yong chang jing sycj</span></th><th>作用范围<span class="pagefind-pinyin" aria-hidden="true">zuoyongfanwei zuo yong fan wei zyfw</span></th><th>关键特性<span class="pagefind-pinyin" aria-hidden="true">guanjiantexing guan jian te xing gjtx</span></th></tr></thead><tbody><tr><td><strong>useScrollStyles</strong></td><td>需要影响整个页面滚动条（如全局主题）<span class="pagefind-pinyin" aria-hidden="true">xuyaoyingxiangzhenggeyemiangundongtiao（ruquanjuzhuti） xu yao ying xiang zheng ge ye mian gun dong tiao （ ru quan ju zhu ti ） xyyxzgymgdt（rqjzt）</span></td><td>全局 <code>:root</code><span class="pagefind-pinyin" aria-hidden="true">quanju quan ju qj </span></td><td>自动注入/清理全局变量<br>响应式 <code>ComputedRef</code><br>生命周期安全<span class="pagefind-pinyin" aria-hidden="true">zidongzhuru/qingliquanjubianliangxiangyingshi shengmingzhouqianquan zi dong zhu ru / qing li quan ju bian liang xiang ying shi sheng ming zhou qi an quan zdzr/qlqjblxys smzqaq</span></td></tr><tr><td><strong>useScrollVariables</strong></td><td>自定义 Scrollbar 容器或局部溢出区域<span class="pagefind-pinyin" aria-hidden="true">zidingyi Scrollbar rongqihuojubuyichuquyu zi ding yi Scrollbar rong qi huo ju bu yi chu qu yu zdy rqhjbycqy</span></td><td>局部容器<span class="pagefind-pinyin" aria-hidden="true">juburongqi ju bu rong qi jbrq</span></td><td>纯对象返回，无副作用<br>自动单位处理<br>变量名前缀隔离<span class="pagefind-pinyin" aria-hidden="true">chunduixiangfanhui，wufuzuoyongzidongdanweichulibianliangmingqianzhuigeli chun dui xiang fan hui ， wu fu zuo yong zi dong dan wei chu li bian liang ming qian zhui ge li cdxfh，wfzyzddwclblmqzgl</span></td></tr></tbody></table><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to “核心特性”">​</a><span class="pagefind-pinyin" aria-hidden="true">hexintexing he xin te xing hxtx </span></h2><table tabindex="0"><thead><tr><th>特性<span class="pagefind-pinyin" aria-hidden="true">texing te xing tx</span></th><th>说明<span class="pagefind-pinyin" aria-hidden="true">shuoming shuo ming sm</span></th></tr></thead><tbody><tr><td><strong>全局样式自动生命周期管理</strong><span class="pagefind-pinyin" aria-hidden="true">quanjuyangshizidongshengmingzhouqiguanli quan ju yang shi zi dong sheng ming zhou qi guan li qjyszdsmzqgl</span></td><td><code>onMounted</code> 注入 <code>:root</code> 变量，<code>onUnmounted</code> 自动移除，防止样式泄漏<span class="pagefind-pinyin" aria-hidden="true"> zhuru bianliang， zidongyichu，fangzhiyangshixielou zhu ru bian liang ， zi dong yi chu ， fang zhi yang shi xie lou zr bl，zdyc，fzysxl</span></td></tr><tr><td><strong>响应式局部样式</strong><span class="pagefind-pinyin" aria-hidden="true">xiangyingshijubuyangshi xiang ying shi ju bu yang shi xysjbys</span></td><td><code>useScrollStyles</code> 返回 <code>ComputedRef&lt;CSSProperties&gt;</code>，支持 props 变化实时更新<span class="pagefind-pinyin" aria-hidden="true"> fanhui ，zhichi props bianhuashishigengxin fan hui ， zhi chi props bian hua shi shi geng xin fh zc bhssgx</span></td></tr><tr><td><strong>单位智能处理</strong><span class="pagefind-pinyin" aria-hidden="true">danweizhinengchuli dan wei zhi neng chu li dwzncl</span></td><td><code>scrollWidth</code>/<code>scrollHeight</code> 数字自动加 <code>px</code>，字符串直接透传<span class="pagefind-pinyin" aria-hidden="true">/ shuzizidongjia ，zifuchuanzhijietouchuan / shu zi zi dong jia ， zi fu chuan zhi jie tou chuan /szzdj zfczjtc</span></td></tr><tr><td><strong>变量名隔离</strong><span class="pagefind-pinyin" aria-hidden="true">bianliangminggeli bian liang ming ge li blmgl</span></td><td>局部使用 <code>--scrollbar-container-*</code> 前缀，避免与全局冲突<span class="pagefind-pinyin" aria-hidden="true">jubushiyong qianzhui，bimianyuquanjuchongtu ju bu shi yong qian zhui ， bi mian yu quan ju chong tu jbsy qz，bmyqjct</span></td></tr><tr><td><strong>全局变量统一</strong><span class="pagefind-pinyin" aria-hidden="true">quanjubianliangtongyi quan ju bian liang tong yi qjblty</span></td><td>使用 <code>--global-scroll-*</code> 系列，确保整个库滚动条视觉一致<span class="pagefind-pinyin" aria-hidden="true">shiyong xilie，quebaozhenggekugundongtiaoshijueyizhi shi yong xi lie ， que bao zheng ge ku gun dong tiao shi jue yi zhi sy xl，qbzgkgdtsjyz</span></td></tr><tr><td><strong>SSR 安全</strong><span class="pagefind-pinyin" aria-hidden="true">SSR anquan SSR an quan Saq</span></td><td>DOM 操作仅在客户端执行（隐式通过 onMounted/onUnmounted）<span class="pagefind-pinyin" aria-hidden="true">DOM caozuojinzaikehuduanzhihang（yinshitongguo onMounted/onUnmounted） DOM cao zuo jin zai ke hu duan zhi hang （ yin shi tong guo onMounted/onUnmounted） Dczjzkhdzh（ystg </span></td></tr></tbody></table><h2 id="设计价值" tabindex="-1">设计价值 <a class="header-anchor" href="#设计价值" aria-label="Permalink to “设计价值”">​</a><span class="pagefind-pinyin" aria-hidden="true">shejijiazhi she ji jia zhi sjjz </span></h2><p>这两个工具共同构成了组件库完整的滚动条样式解决方案：<span class="pagefind-pinyin" aria-hidden="true">zhelianggegongjugongtonggouchenglezujiankuwanzhengdegundongtiaoyangshijiejuefangan： zhe liang ge gong ju gong tong gou cheng le zu jian ku wan zheng de gun dong tiao yang shi jie jue fang an ： zlggjgtgclzjkwzdgdtysjjfa：</span></p><p>全局一致性：通过 useScrollStyles 确保所有原生滚动条在主题切换时同步更新 局部灵活性：useScrollVariables 支持独立容器自定义外观 安全可靠：自动清理机制杜绝样式污染，适合动态加载组件 与主题系统无缝衔接：变量名规范、颜色 props 统一 减少重复：所有滚动条相关样式逻辑集中于此，组件无需关心实现细节<span class="pagefind-pinyin" aria-hidden="true">quanjuyizhixing：tongguo useScrollStyles quebaosuoyouyuanshenggundongtiaozaizhutiqiehuanshitongbugengxinjubulinghuoxing：useScrollVariables zhichidulirongqizidingyiwaiguananquankekao：zidongqinglijizhidujueyangshiwuran，shihedongtaijiazaizujianyuzhutixitongwufengxianjie：bianliangmingguifan、yanse props tongyijianshaozhongfu：suoyougundongtiaoxiangguanyangshiluojijizhongyuci，zujianwuxuguanxinshixianxijie quan ju yi zhi xing ： tong guo useScrollStyles que bao suo you yuan sheng gun dong tiao zai zhu ti qie huan shi tong bu geng xin ju bu ling huo xing ：useScrollVariables zhi chi du li rong qi zi ding yi wai guan an quan ke kao ： zi dong qing li ji zhi du jue yang shi wu ran ， shi he dong tai jia zai zu jian yu zhu ti xi tong wu feng xian jie ： bian liang ming gui fan 、 yan se props tong yi jian shao zhong fu ： suo you gun dong tiao xiang guan yang shi luo ji ji zhong yu ci ， zu jian wu xu guan xin shi xian xi jie qjyzx：tg qbsyysgdtzztqhstbgxjblhx：zcdlrqzdywgaqkk：zdqljzdjyswr，shdtjzzjyztxtwfxj：blmgf、ys tyjszf：sygdtxgysljjzyc，zjwxgxsxxj</span></p>',17)])])}const p=i(e,[["render",o]]);export{y as __pageData,p as default};
